/** @import { AwaitExpression } from 'estree' */
/** @import { Context } from '../types' */
import * as e from '../../../errors.js';

/**
 * @param {AwaitExpression} node
 * @param {Context} context
 */
export function AwaitExpression(node, context) {
	let suspend = context.state.ast_type === 'instance' && context.state.function_depth === 1;

	if (context.state.expression) {
		context.state.expression.has_await = true;
		// Only suspend if we're not inside a derived/function context (function_depth > 1)
		// Template expressions at the top level (function_depth === 0) should suspend
		// Template expressions in @const or $derived (function_depth > 1) should not suspend
		if (context.state.function_depth <= 1) {
			suspend = true;
		}
	}

	// disallow top-level `await` or `await` in template expressions
	// unless a) in runes mode and b) opted into `experimental.async`
	if (suspend) {
		if (!context.state.options.experimental.async) {
			e.experimental_async(node);
		}

		if (!context.state.analysis.runes) {
			e.legacy_await_invalid(node);
		}
	}

	context.next();
}

